{
  "decision_summary": "The chip temperature (89.26°C) exceeds the limit (85.0°C). Since geometry changes are hitting legality limits and recent improvements have stalled, the strategy shifts to material tuning. Increasing the heat spreader conductivity is the highest priority lever to improve lateral heat spreading and reduce the peak temperature.",
  "changes": [
    {
      "path": "materials.spreader_material.conductivity",
      "action": "set",
      "old": 500.0,
      "new": 1000.0,
      "reason": "Increasing spreader conductivity enhances lateral heat diffusion, lowering the thermal gradient and reducing the chip's peak temperature. This is the primary recommended lever when geometry adjustments stall."
    }
  ],
  "expected_effects": [
    "Reduce chip_max_temperature below 85.0°C",
    "Improve lateral heat distribution across the spreader layer"
  ],
  "risk_notes": [
    "The proposed value (1000.0) exceeds the documented upper bound of 500.0 for this variable; if strict bounds enforcement prevents this, fallback to maximizing within bounds or adjusting base_material conductivity.",
    "Diminishing returns may occur if the bottleneck shifts to the base plate or boundary conditions rather than the spreader itself."
  ]
}
